parameters.jsCode:
// Parse AI Agent response and format for the extension
const input = $input.first().json;

try {
  // AI Agent returns { output: '...' } with the text response
  let rawText = '';

  if (input.output) {
    rawText = input.output;
  } else if (input.text) {
    rawText = input.text;
  } else if (typeof input === 'string') {
    rawText = input;
  } else {
    // Search all string properties for JSON
    for (const key of Object.keys(input)) {
      const val = input[key];
      if (typeof val === 'string' && val.includes('comments')) {
        rawText = val;
        break;
      }
    }
    if (!rawText) rawText = JSON.stringify(input);
  }

  // Extract JSON from the response
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (!jsonMatch) {
    throw new Error('No JSON found in AI response: ' + rawText.substring(0, 200));
  }

  const parsed = JSON.parse(jsonMatch[0]);
  const comments = parsed.comments || parsed.data;

  if (!Array.isArray(comments) || comments.length === 0) {
    throw new Error('Invalid comments array in response');
  }

  const formatted = comments.map((c, i) => ({
    text: c.text || c.content || String(c),
    type: c.type || (i === 0 ? 'short' : 'mid')
  }));

  return [{
    json: {
      success: true,
      data: formatted,
      error: null
    }
  }];
} catch (e) {
  return [{
    json: {
      success: false,
      data: null,
      error: 'Failed to parse AI response: ' + e.message
    }
  }];
}
